import React, { useState } from 'react';
import './App.css';
import IPQCPage from './components/IPQCPage';
import IQCPage from './components/IQCPage';

// ========== MAIN APP ==========
function App() {
  const [activeModule, setActiveModule] = useState('ipqc'); // 'ipqc' | 'iqc'

  return (
    <div className="app-root">
      <header className="app-header">
        <div className="hdr-inner">
          <div className="brand">
            <div className="brand-icon">🏭</div>
            <div>
              <h1>Gautam Solar — QC System</h1>
              <span className="brand-sub">IPQC & IQC Quality Control • OCR • Excel • Scanned PDF</span>
            </div>
          </div>
          <nav className="nav-tabs">
            <button className={`nav-tab ${activeModule === 'ipqc' ? 'active' : ''}`} onClick={() => setActiveModule('ipqc')}>
              🔬 IPQC
            </button>
            <button className={`nav-tab ${activeModule === 'iqc' ? 'active' : ''}`} onClick={() => setActiveModule('iqc')}>
              📦 IQC
            </button>
          </nav>
        </div>
      </header>

      <main className="main-area">
        {activeModule === 'ipqc' ? <IPQCPage /> : <IQCPage />}
      </main>
    </div>
  );
}

// ========== CHECKLIST TAB ==========
function ChecklistTab() {
  const [loading, setLoading] = useState(false);
  const [checklists, setChecklists] = useState([]);
  const [error, setError] = useState('');
  const [processing, setProcessing] = useState(null);
  const [processResults, setProcessResults] = useState({});
  const [comparisonItem, setComparisonItem] = useState(null);
  const [savingPdf, setSavingPdf] = useState(false);

  const [filterDate, setFilterDate] = useState('');
  const [filterShift, setFilterShift] = useState('');
  const [filterLine, setFilterLine] = useState('');

  const fetchAll = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const res = await axios.post(`${API_BASE}/ipqc-checklist/fetch`, {});
      if (res.data.success) {
        setChecklists(res.data.data || []);
        if ((res.data.data || []).length === 0) setError('No IPQC checklists found.');
      } else {
        setError(res.data.error || 'Fetch failed');
      }
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const filtered = checklists.filter(item => {
    if (filterDate && item.date !== filterDate) return false;
    if (filterShift && item.Shift !== filterShift) return false;
    if (filterLine && item.Line !== filterLine) return false;
    return true;
  });

  const uniqueDates = [...new Set(checklists.map(c => c.date).filter(Boolean))].sort().reverse();
  const uniqueShifts = [...new Set(checklists.map(c => c.Shift).filter(Boolean))];
  const uniqueLines = [...new Set(checklists.map(c => c.Line).filter(Boolean))].sort();
  const processedCount = Object.keys(processResults).length;

  const handleProcess = async (checklist, index) => {
    setProcessing(index);
    setError('');
    try {
      const res = await axios.post(`${API_BASE}/ipqc-checklist/process-item`, { checklist });
      if (res.data.success) {
        setProcessResults(prev => ({ ...prev, [index]: res.data }));
      } else {
        setError(res.data.error || 'Processing failed');
      }
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally {
      setProcessing(null);
    }
  };

  const handleDownload = (filename) => {
    window.open(`${API_BASE}/ipqc-ocr/download/${filename}`, '_blank');
  };

  const handleSavePdf = async (checklist) => {
    setSavingPdf(true);
    try {
      const res = await axios.post(`${API_BASE}/ipqc-ocr/save-original-pdfs`, { checklist });
      if (res.data.success) {
        for (const f of res.data.files) {
          if (!f.error) window.open(`${API_BASE}/ipqc-ocr/download/${f.filename}`, '_blank');
        }
      }
    } catch (e) {
      setError('Failed to save PDFs: ' + e.message);
    } finally {
      setSavingPdf(false);
    }
  };

  // ===== COMPARISON VIEW =====
  if (comparisonItem) {
    return (
      <ComparisonPanel
        checklist={comparisonItem.checklist}
        result={comparisonItem.result}
        onBack={() => setComparisonItem(null)}
        onDownloadExcel={() => handleDownload(comparisonItem.result.outputFile)}
        onDownloadHumanExcel={() => handleDownload(comparisonItem.result.humanOutputFile)}
        humanExcelGenerated={comparisonItem.result.humanExcelGenerated}
        scannedPdfGenerated={comparisonItem.result.scannedPdfGenerated}
        onDownloadScannedPdf={() => handleDownload(comparisonItem.result.scannedPdfFile)}
        onSavePdf={() => handleSavePdf(comparisonItem.checklist)}
        savingPdf={savingPdf}
      />
    );
  }

  // ===== TABLE VIEW =====
  return (
    <>
      {/* Stats Cards */}
      <div className="stats-row">
        <div className="stat-card">
          <div className="stat-icon bg-blue">📋</div>
          <div className="stat-body">
            <span className="stat-val">{checklists.length}</span>
            <span className="stat-lbl">Total Checklists</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon bg-green">✅</div>
          <div className="stat-body">
            <span className="stat-val">{processedCount}</span>
            <span className="stat-lbl">Processed</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon bg-amber">⏳</div>
          <div className="stat-body">
            <span className="stat-val">{Math.max(0, filtered.length - processedCount)}</span>
            <span className="stat-lbl">Pending</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon bg-purple">📄</div>
          <div className="stat-body">
            <span className="stat-val">{filtered.length}</span>
            <span className="stat-lbl">Showing</span>
          </div>
        </div>
      </div>

      {/* Main Card */}
      <div className="card">
        <div className="card-top">
          <h2>📋 IPQC Checklists</h2>
          <button onClick={fetchAll} disabled={loading} className="btn btn-ghost">
            {loading ? <span className="spin-sm"></span> : '🔄'} Refresh
          </button>
        </div>

        {/* Filters */}
        <div className="filters">
          <div className="flt-group">
            <label>Date</label>
            <select value={filterDate} onChange={e => setFilterDate(e.target.value)}>
              <option value="">All ({uniqueDates.length})</option>
              {uniqueDates.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <div className="flt-group">
            <label>Shift</label>
            <select value={filterShift} onChange={e => setFilterShift(e.target.value)}>
              <option value="">All</option>
              {uniqueShifts.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div className="flt-group">
            <label>Line</label>
            <select value={filterLine} onChange={e => setFilterLine(e.target.value)}>
              <option value="">All</option>
              {uniqueLines.map(l => <option key={l} value={l}>{l}</option>)}
            </select>
          </div>
        </div>

        {error && <div className="alert alert-error">❌ {error}</div>}
        {loading && checklists.length === 0 && (
          <div className="alert alert-info"><span className="spin-sm"></span> Loading all checklists...</div>
        )}

        {/* Table */}
        {filtered.length > 0 && (
          <div className="table-wrap">
            <table className="data-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Date</th>
                  <th>Line</th>
                  <th>Shift</th>
                  <th>Pages</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((item, idx) => {
                  const gi = checklists.indexOf(item);
                  const result = processResults[gi];
                  const isProc = processing === gi;

                  return (
                    <tr key={gi} className={result ? 'row-done' : ''}>
                      <td className="td-num">{idx + 1}</td>
                      <td className="td-date">{item.date || '—'}</td>
                      <td><span className="badge badge-line">{item.Line || '—'}</span></td>
                      <td>
                        <span className={`badge badge-shift ${(item.Shift || '').toLowerCase()}`}>
                          {item.Shift === 'Day' ? '☀️' : '🌙'} {item.Shift || '—'}
                        </span>
                      </td>
                      <td><span className="badge badge-pages">{item.totalPages || 0}</span></td>
                      <td>
                        {isProc ? (
                          <span className="status status-proc"><span className="spin-sm"></span> Processing...</span>
                        ) : result ? (
                          <span className="status status-done">✅ Done</span>
                        ) : (
                          <span className="status status-pend">⏳ Pending</span>
                        )}
                      </td>
                      <td>
                        <div className="actions-cell">
                          {isProc ? (
                            <span className="text-muted">Please wait...</span>
                          ) : result ? (
                            <>
                              <button
                                className="btn btn-sm btn-primary"
                                onClick={() => setComparisonItem({ checklist: item, result, index: gi })}
                              >
                                📊 Compare
                              </button>
                              {result.excelGenerated && (
                                <button className="btn btn-sm btn-success" onClick={() => handleDownload(result.outputFile)}>
                                  📥 System
                                </button>
                              )}
                              {result.humanExcelGenerated && (
                                <button className="btn btn-sm btn-warning" onClick={() => handleDownload(result.humanOutputFile)}>
                                  ✍️ Real
                                </button>
                              )}
                              {result.scannedPdfGenerated && (
                                <button className="btn btn-sm btn-danger" onClick={() => handleDownload(result.scannedPdfFile)}>
                                  📄 Scan PDF
                                </button>
                              )}
                            </>
                          ) : (
                            <button
                              className="btn btn-sm btn-primary"
                              onClick={() => handleProcess(item, gi)}
                              disabled={processing !== null || item.totalPages === 0}
                            >
                              🚀 Process
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </>
  );
}

// ========== COMPARISON PANEL ==========
function ComparisonPanel({ checklist, result, onBack, onDownloadExcel, onDownloadHumanExcel, humanExcelGenerated, scannedPdfGenerated, onDownloadScannedPdf, onSavePdf, savingPdf }) {
  const [activePg, setActivePg] = useState(0);

  const pdfPages = result.pdfUrls || checklist.pdfPages || [];
  const extracted = result.extractedData || [];
  const st = result.stats || {};
  const pgStats = st.pageStats || [];

  // Stats - now with proper scan vs serial distinction
  const totalPages = st.totalPages || pdfPages.length;
  const pagesScanned = st.pagesScanned || extracted.filter(p => (p.rawText?.length || 0) > 0).length;
  const pagesWithAnyData = st.pagesWithAnyData || extracted.filter(p =>
    (p.serialNumbers?.length || 0) > 0 || (p.temperatures?.length || 0) > 0 ||
    (p.times?.length || 0) > 0 || (p.dates?.length || 0) > 0
  ).length;
  const pagesWithSerials = st.pagesWithSerials || extracted.filter(p => (p.serialNumbers?.length || 0) > 0).length;
  const totalSerials = st.totalSerials || extracted.reduce((s, p) => s + (p.serialNumbers?.length || 0), 0);
  const totalTemps = st.totalTemps || extracted.reduce((s, p) => s + (p.temperatures?.length || 0), 0);
  const totalDims = st.totalDimensions || extracted.reduce((s, p) => s + (p.dimensions?.length || 0), 0);
  const totalTimes = st.totalTimes || extracted.reduce((s, p) => s + (p.times?.length || 0), 0);
  const totalDates = st.totalDates || extracted.reduce((s, p) => s + (p.dates?.length || 0), 0);
  const totalChars = st.totalChars || extracted.reduce((s, p) => s + (p.rawText?.length || 0), 0);
  const pagesWithErrors = st.pagesWithErrors || extracted.filter(p => p.error).length;

  const scanPercent = st.scanPercent || (totalPages > 0 ? Math.round((pagesScanned / totalPages) * 100) : 0);
  const dataPercent = st.dataFetchPercent || (totalPages > 0 ? Math.round((pagesWithAnyData / totalPages) * 100) : 0);
  const serialPercent = st.serialPercent || (totalPages > 0 ? Math.round((pagesWithSerials / totalPages) * 100) : 0);

  // Current page data
  const currentPdf = pdfPages[activePg];
  const currentUrl = currentPdf?.url || currentPdf;
  const currentData = extracted[activePg];
  const currentPgStat = pgStats[activePg] || null;

  // Page scan status helper
  const getPageScanStatus = (i) => {
    if (pgStats[i]) return pgStats[i];
    const pg = extracted[i];
    if (!pg) return { scanned: false, chars: 0, serials: 0, temps: 0, times: 0, dates: 0, dims: 0, error: null };
    return {
      scanned: (pg.rawText?.length || 0) > 0,
      chars: pg.rawText?.length || 0,
      serials: pg.serialNumbers?.length || 0,
      temps: pg.temperatures?.length || 0,
      times: pg.times?.length || 0,
      dates: pg.dates?.length || 0,
      dims: pg.dimensions?.length || 0,
      error: pg.error || null
    };
  };

  const proxyUrl = currentUrl
    ? `${API_BASE}/ipqc-ocr/proxy-pdf?url=${encodeURIComponent(currentUrl)}`
    : null;

  return (
    <div className="comparison">
      {/* Header */}
      <div className="comp-header">
        <div className="comp-left">
          <button className="btn btn-ghost btn-back" onClick={onBack}>← Back to List</button>
          <div className="comp-title">
            <h2>📊 IPQC Comparison View</h2>
            <div className="comp-meta">
              <span className="meta-tag">📅 {checklist.date || '—'}</span>
              <span className="meta-tag">🏭 Line {checklist.Line || '—'}</span>
              <span className={`meta-tag shift-tag ${(checklist.Shift || '').toLowerCase()}`}>
                {checklist.Shift === 'Day' ? '☀️' : '🌙'} {checklist.Shift || '—'}
              </span>
            </div>
          </div>
        </div>
        <div className="comp-right comp-circles">
          <CircleProgress percent={scanPercent} size={90} strokeWidth={7} label="OCR Scan" />
          <CircleProgress percent={dataPercent} size={90} strokeWidth={7} label="Data Found" />
          <CircleProgress percent={serialPercent} size={90} strokeWidth={7} label="Serials" />
        </div>
      </div>

      {/* Per-page scan overview */}
      <div className="scan-overview">
        <div className="scan-overview-hdr">
          <h3>📡 Page-wise Scan Status</h3>
          <span className="scan-total">{totalChars.toLocaleString()} chars OCR'd total</span>
        </div>
        <div className="scan-grid">
          {pdfPages.map((p, i) => {
            const pg = p?.page || i + 1;
            const stat = getPageScanStatus(i);
            return (
              <div
                key={i}
                className={`scan-cell ${activePg === i ? 'scan-active' : ''} ${stat.error ? 'scan-error' : stat.scanned ? 'scan-ok' : 'scan-fail'}`}
                onClick={() => setActivePg(i)}
              >
                <div className="scan-cell-top">
                  <span className="scan-pg">Page {pg}</span>
                  <span className="scan-status-icon">{stat.error ? '❌' : stat.scanned ? '✅' : '⚠️'}</span>
                </div>
                <div className="scan-cell-chars">{stat.chars.toLocaleString()} chars</div>
                <div className="scan-cell-items">
                  {stat.serials > 0 && <span className="sci sci-serial">{stat.serials} SN</span>}
                  {stat.temps > 0 && <span className="sci sci-temp">{stat.temps} T°</span>}
                  {stat.times > 0 && <span className="sci sci-time">{stat.times} ⏱</span>}
                  {stat.dates > 0 && <span className="sci sci-date">{stat.dates} 📅</span>}
                  {stat.dims > 0 && <span className="sci sci-dim">{stat.dims} 📏</span>}
                  {stat.serials === 0 && stat.temps === 0 && stat.times === 0 && stat.dates === 0 && stat.dims === 0 && (
                    <span className="sci sci-none">raw text only</span>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Summary Stats */}
      <div className="comp-stats-row">
        <div className="comp-stat-card">
          <span className="csc-val">{totalPages}</span>
          <span className="csc-lbl">Total Pages</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val csc-green">{pagesScanned}/{totalPages}</span>
          <span className="csc-lbl">Scanned OK</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val">{totalSerials}</span>
          <span className="csc-lbl">Serial Numbers</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val">{totalTemps}</span>
          <span className="csc-lbl">Temperatures</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val">{totalTimes}</span>
          <span className="csc-lbl">Times</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val">{totalDates}</span>
          <span className="csc-lbl">Dates</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val">{totalDims}</span>
          <span className="csc-lbl">Dimensions</span>
        </div>
        <div className="comp-stat-card">
          <span className="csc-val">{result.excelGenerated ? '✅' : '❌'}</span>
          <span className="csc-lbl">Excel Ready</span>
        </div>
      </div>

      {/* Page Navigation Tabs */}
      <div className="page-nav">
        {pdfPages.map((p, i) => {
          const pg = p?.page || i + 1;
          const stat = getPageScanStatus(i);
          const hasItems = stat.serials > 0 || stat.temps > 0 || stat.times > 0 || stat.dates > 0;
          return (
            <button
              key={i}
              className={`page-tab ${activePg === i ? 'active' : ''} ${stat.error ? 'tab-error' : stat.scanned ? (hasItems ? 'has-data' : 'scanned-only') : ''}`}
              onClick={() => setActivePg(i)}
            >
              <span className="page-tab-status">{stat.error ? '❌' : stat.scanned ? '✅' : '⚠️'}</span>
              Page {pg}
              {stat.serials > 0 && <span className="page-tab-badge">{stat.serials} SN</span>}
            </button>
          );
        })}
      </div>

      {/* Split View: PDF Left | Data Right */}
      <div className="split-view">
        {/* LEFT: PDF Viewer */}
        <div className="split-panel split-pdf">
          <div className="panel-top">
            <h3>📄 Original IPQC PDF — Page {pdfPages[activePg]?.page || activePg + 1}</h3>
            <button className="btn btn-sm btn-outline" onClick={onSavePdf} disabled={savingPdf}>
              {savingPdf ? '⏳ Saving...' : '💾 Save All PDFs'}
            </button>
          </div>
          <div className="pdf-frame">
            {proxyUrl ? (
              <iframe src={proxyUrl} title={`IPQC PDF Page ${activePg + 1}`} />
            ) : (
              <div className="pdf-empty">
                <span className="empty-icon">📄</span>
                <p>No PDF available for this page</p>
              </div>
            )}
          </div>
        </div>

        {/* RIGHT: Extracted Data */}
        <div className="split-panel split-data">
          <div className="panel-top">
            <h3>📊 Extracted Data — Page {pdfPages[activePg]?.page || activePg + 1}
              {currentPgStat || currentData ? (
                <span className="panel-scan-badge">
                  {(currentPgStat?.scanned || currentData?.rawText?.length > 0) ? '✅ Scanned' : '⚠️ Not Scanned'}
                </span>
              ) : null}
            </h3>
            {result.excelGenerated && (
              <button className="btn btn-sm btn-success" onClick={onDownloadExcel}>📥 System</button>
            )}
            {humanExcelGenerated && (
              <button className="btn btn-sm btn-warning" onClick={onDownloadHumanExcel}>✍️ Real</button>
            )}
            {scannedPdfGenerated && (
              <button className="btn btn-sm btn-danger" onClick={onDownloadScannedPdf}>📄 Scan PDF</button>
            )}
          </div>
          <div className="data-content">
            {currentData ? (
              currentData.error ? (
                <div className="alert alert-error">Error: {currentData.error}</div>
              ) : (
                <>
                  {/* Mini stats for this page */}
                  <div className="page-mini-stats">
                    <div className={`pms ${(currentData.rawText?.length || 0) > 0 ? 'pms-ok' : 'pms-fail'}`}>
                      <span className="pms-num">{(currentData.rawText?.length || 0).toLocaleString()}</span>
                      <span className="pms-txt">OCR Chars</span>
                    </div>
                    <div className={`pms ${(currentData.serialNumbers?.length || 0) > 0 ? 'pms-ok' : ''}`}>
                      <span className="pms-num">{currentData.serialNumbers?.length || 0}</span>
                      <span className="pms-txt">Serials</span>
                    </div>
                    <div className={`pms ${(currentData.temperatures?.length || 0) > 0 ? 'pms-ok' : ''}`}>
                      <span className="pms-num">{currentData.temperatures?.length || 0}</span>
                      <span className="pms-txt">Temps</span>
                    </div>
                    <div className={`pms ${(currentData.times?.length || 0) > 0 ? 'pms-ok' : ''}`}>
                      <span className="pms-num">{currentData.times?.length || 0}</span>
                      <span className="pms-txt">Times</span>
                    </div>
                    <div className={`pms ${(currentData.dates?.length || 0) > 0 ? 'pms-ok' : ''}`}>
                      <span className="pms-num">{currentData.dates?.length || 0}</span>
                      <span className="pms-txt">Dates</span>
                    </div>
                  </div>

                  {/* Serial Numbers */}
                  {currentData.serialNumbers?.length > 0 && (
                    <div className="data-section">
                      <h4>🔢 Serial Numbers ({currentData.serialNumbers.length})</h4>
                      <div className="chip-grid">
                        {currentData.serialNumbers.map((s, i) => (
                          <span key={i} className="chip chip-serial">{s}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Temperatures */}
                  {currentData.temperatures?.length > 0 && (
                    <div className="data-section">
                      <h4>🌡️ Temperatures ({currentData.temperatures.length})</h4>
                      <div className="chip-grid">
                        {currentData.temperatures.map((t, i) => (
                          <span key={i} className="chip chip-temp">{t}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Times */}
                  {currentData.times?.length > 0 && (
                    <div className="data-section">
                      <h4>🕐 Times ({currentData.times.length})</h4>
                      <div className="chip-grid">
                        {currentData.times.map((t, i) => (
                          <span key={i} className="chip chip-time">{t}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Dates */}
                  {currentData.dates?.length > 0 && (
                    <div className="data-section">
                      <h4>📅 Dates ({currentData.dates.length})</h4>
                      <div className="chip-grid">
                        {currentData.dates.map((d, i) => (
                          <span key={i} className="chip chip-date">{d}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Dimensions */}
                  {currentData.dimensions?.length > 0 && (
                    <div className="data-section">
                      <h4>📏 Dimensions ({currentData.dimensions.length})</h4>
                      <div className="chip-grid">
                        {currentData.dimensions.map((d, i) => (
                          <span key={i} className="chip chip-dim">{d}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Percentages */}
                  {currentData.percentages?.length > 0 && (
                    <div className="data-section">
                      <h4>📊 Percentages ({currentData.percentages.length})</h4>
                      <div className="chip-grid">
                        {currentData.percentages.map((p, i) => (
                          <span key={i} className="chip chip-dim">{p}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Raw OCR Text */}
                  {currentData.rawText && (
                    <details className="raw-text-toggle">
                      <summary>📝 Raw OCR Text ({currentData.rawText.length.toLocaleString()} characters)</summary>
                      <pre className="raw-text-pre">{currentData.rawText}</pre>
                    </details>
                  )}

                  {/* No structured data - but page IS scanned */}
                  {!currentData.serialNumbers?.length && !currentData.temperatures?.length && !currentData.times?.length && !currentData.dates?.length && !currentData.dimensions?.length && currentData.rawText?.length > 0 && (
                    <div className="no-data-box scan-success-box">
                      <span>✅</span>
                      <p>Page scanned successfully ({currentData.rawText.length.toLocaleString()} chars)</p>
                      <p className="no-data-sub">No structured fields (serials, temps, etc.) were extracted from this page — this is normal for cover/header pages.</p>
                    </div>
                  )}

                  {/* Truly empty */}
                  {(!currentData.rawText || currentData.rawText.length === 0) && (
                    <div className="no-data-box">
                      <span>❌</span>
                      <p>Page was NOT scanned — OCR returned empty text</p>
                    </div>
                  )}
                </>
              )
            ) : (
              <div className="no-data-box">
                <span>📭</span>
                <p>No data available for this page</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Bottom Summary Bar */}
      <div className="comp-footer">
        <div className="comp-footer-info">
          <h3>📊 Overall Extraction Summary</h3>
          <div className="progress-bars-group">
            <div className="progress-row">
              <span className="prog-lbl">OCR Scan</span>
              <div className="progress-bar"><div className="progress-fill prog-scan" style={{ width: `${scanPercent}%` }}></div></div>
              <span className="prog-pct">{scanPercent}%</span>
            </div>
            <div className="progress-row">
              <span className="prog-lbl">Data Found</span>
              <div className="progress-bar"><div className="progress-fill prog-data" style={{ width: `${dataPercent}%` }}></div></div>
              <span className="prog-pct">{dataPercent}%</span>
            </div>
            <div className="progress-row">
              <span className="prog-lbl">Serials</span>
              <div className="progress-bar"><div className="progress-fill prog-serial" style={{ width: `${serialPercent}%` }}></div></div>
              <span className="prog-pct">{serialPercent}%</span>
            </div>
          </div>
          <p className="summary-text">
            {pagesScanned}/{totalPages} pages scanned &bull; {pagesWithErrors > 0 ? `${pagesWithErrors} errors &bull; ` : ''}{totalSerials} serial numbers &bull; {totalTemps} temperatures &bull; {totalTimes} times &bull; {totalDates} dates
          </p>
        </div>
        <div className="comp-footer-actions">
          {result.excelGenerated && (
            <button className="btn btn-lg btn-success" onClick={onDownloadExcel}>
              📥 Download System Excel
            </button>
          )}
          {humanExcelGenerated && (
            <button className="btn btn-lg btn-warning" onClick={onDownloadHumanExcel}>
              ✍️ Download Real Excel
            </button>
          )}
          {scannedPdfGenerated && (
            <button className="btn btn-lg btn-danger" onClick={onDownloadScannedPdf}>
              📄 Download Scanned PDF
            </button>
          )}
          <button className="btn btn-lg btn-outline" onClick={onSavePdf} disabled={savingPdf}>
            {savingPdf ? '⏳ Saving...' : '💾 Save Original PDFs'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ========== MANUAL OCR TAB ==========
function OcrTab() {
  const [pdfUrls, setPdfUrls] = useState('');
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState('');
  const [error, setError] = useState('');
  const [result, setResult] = useState(null);
  const [extractedData, setExtractedData] = useState(null);

  const handleProcess = async () => {
    if (!pdfUrls.trim()) { setError('Enter PDF URLs'); return; }
    setLoading(true);
    setStatus('Processing...');
    setError('');
    setResult(null);
    setExtractedData(null);

    try {
      const urls = pdfUrls.split('\n').map(u => u.trim()).filter(Boolean);
      setStatus(`Processing ${urls.length} PDF(s) with Azure OCR...`);
      const res = await axios.post(`${API_BASE}/ipqc-ocr/process-from-urls`, { pdfUrls: urls });
      if (res.data.success) {
        setResult(res.data);
        setExtractedData(res.data.extractedData);
        setStatus('✅ OCR Complete! Excel ready for download.');
      } else {
        setError(res.data.error || 'Failed');
        setStatus('');
      }
    } catch (e) {
      setError(e.response?.data?.error || e.message);
      setStatus('');
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = () => {
    if (result?.outputFile) {
      const fn = result.outputFile.includes('\\') || result.outputFile.includes('/')
        ? result.outputFile.split(/[\\\/]/).pop()
        : result.outputFile;
      window.open(`${API_BASE}/ipqc-ocr/download/${fn}`, '_blank');
    }
  };

  return (
    <div className="card">
      <h2 className="card-title">🔗 Manual OCR Processing</h2>
      <p className="card-desc">Paste PDF URLs to process through Azure OCR and generate Excel.</p>

      <div className="input-section">
        <label>Enter PDF URLs (one per line):</label>
        <textarea
          value={pdfUrls}
          onChange={e => setPdfUrls(e.target.value)}
          placeholder={`https://example.com/page1.pdf\nhttps://example.com/page2.pdf`}
          rows={5}
          disabled={loading}
        />
      </div>

      <div className="btn-row">
        <button onClick={handleProcess} disabled={loading || !pdfUrls.trim()} className="btn btn-primary">
          {loading ? <><span className="spin-sm white"></span> Processing...</> : '🚀 Process OCR'}
        </button>
        {result && (
          <button onClick={handleDownload} className="btn btn-success">📥 System Excel</button>
        )}
        {result?.humanExcelGenerated && (
          <button onClick={() => {
            const fn = result.humanOutputFile.includes('\\') || result.humanOutputFile.includes('/')
              ? result.humanOutputFile.split(/[\\\/]/).pop()
              : result.humanOutputFile;
            window.open(`${API_BASE}/ipqc-ocr/download/${fn}`, '_blank');
          }} className="btn btn-warning">✍️ Real Excel</button>
        )}
        {result?.scannedPdfGenerated && (
          <button onClick={() => {
            const fn = result.scannedPdfFile.includes('\\') || result.scannedPdfFile.includes('/')
              ? result.scannedPdfFile.split(/[\\\/]/).pop()
              : result.scannedPdfFile;
            window.open(`${API_BASE}/ipqc-ocr/download/${fn}`, '_blank');
          }} className="btn btn-danger">📄 Scanned PDF</button>
        )}
      </div>

      {status && <div className="alert alert-info">{status}</div>}
      {error && <div className="alert alert-error">❌ {error}</div>}

      {extractedData && (
        <div className="ocr-results">
          <h3>📋 Extracted Data</h3>
          {extractedData.serialNumbers?.length > 0 && (
            <div className="data-section">
              <h4>Serial Numbers ({extractedData.serialNumbers.length})</h4>
              <div className="chip-grid">
                {extractedData.serialNumbers.slice(0, 20).map((s, i) => (
                  <span key={i} className="chip chip-serial">{s}</span>
                ))}
                {extractedData.serialNumbers.length > 20 && (
                  <span className="chip chip-more">+{extractedData.serialNumbers.length - 20} more</span>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default App;
